import logging
from typing import Any

import httpx
from fastapi import HTTPException

from tenacity import (
    retry,
    stop_after_delay,
    stop_after_attempt,
    wait_exponential,
    retry_if_exception_type,
    before_sleep_log,
)

from harvest.config import settings

logger = logging.getLogger(__name__)

DEFAULT_TIMEOUT = 30.0

@retry(reraise=True,
       stop=(stop_after_attempt(3) | stop_after_delay(20)),
       wait=wait_exponential(multiplier=1, min=3, max=30),
       retry=retry_if_exception_type(httpx.TimeoutException),
       before_sleep=before_sleep_log(logger, logging.DEBUG))
async def wp_get_page_html(
        page_url: str,
) -> str:
    async with httpx.AsyncClient() as client:
        get_html_resp = await client.get(page_url, timeout=5.0)

    if not get_html_resp.is_success:
        logger.error(get_html_resp)
        raise HTTPException(
            status_code=get_html_resp.status_code,
            detail={
                "code": "http_error",
                "message": get_html_resp.text
            }
        )
    return get_html_resp.text


async def wp_html_to_markdown(
        page_url: str,
        page_html: str,
        readable: bool,
) -> dict[str, Any]:
    async with httpx.AsyncClient() as client:
        convert_resp =  await client.post(
            f"{settings.web_parser_base_url}/html2markdown",
            json={
                "url": page_url,
                "html": page_html,
                "readable": readable
            },
            timeout=DEFAULT_TIMEOUT
        )

    if not convert_resp.is_success:
        logger.error(convert_resp)
        raise HTTPException(
            status_code=convert_resp.status_code,
            detail={
                "code": "http_error",
                "message": convert_resp.text
            }
        )

    return convert_resp.json()


async def wp_markdown_to_blocks(
        page_url: str,
        page_content: str,
) -> dict[str, Any]:
    async with httpx.AsyncClient() as client:
        convert_resp = await client.post(
            f"{settings.web_parser_base_url}/markdown2blocks",
            json={
                "url": page_url,
                "markdown": page_content
            },
            timeout=DEFAULT_TIMEOUT
        )

    if not convert_resp.is_success:
        logger.error(convert_resp)
        raise HTTPException(
            status_code=convert_resp.status_code,
            detail={
                "code": "http_error",
                "message": convert_resp.text
            }
        )

    return convert_resp.json()


async def wp_page_to_markdown(
        access_token: str,
        page_id: str,
) -> dict[str, Any]:
    async with httpx.AsyncClient() as client:
        page_content_resp = await client.post(
            f"{settings.web_parser_base_url}/page2markdown",
            json={
                "access_token": access_token,
                "page_id": page_id,
            },
            timeout=DEFAULT_TIMEOUT
        )

    if not page_content_resp.is_success:
        logger.error(page_content_resp)
        raise HTTPException(
            status_code=page_content_resp.status_code,
            detail={
                "code": "http_error",
                "message": page_content_resp.text
            }
        )

    return page_content_resp.json()

