version: '3'

services:
  db:
    image: postgres:16.1-alpine
    container_name: harvest-postgres
    restart: always
    volumes:
      - pgdata:/var/lib/postgresql/data
    ports:
      - "${DB_PORT:?error}:5432"
    networks:
      - dbnet
    environment:
      POSTGRES_USER: ${DB_USERNAME:?error}
      POSTGRES_PASSWORD: ${DB_PASSWORD:?error}
      POSTGRES_DB: ${DB_NAME:?error}
  web-server:
    container_name: harvest-web-server
    image: harvest-web-server:latest
    restart: always
    volumes:
      - logfiles:/usr/src/app/log
    environment:
      ENV: ${ENV:?error}
      WEB_BASE_URL: ${WEB_BASE_URL:?error}
      WEB_HOST: ${WEB_HOST:?error}
      WEB_PORT: ${WEB_PORT:?error}
      WEB_PARSER_BASE_URL: ${WEB_PARSER_BASE_URL:?error}
      NOTION_OAUTH_CLIENT_ID: ${NOTION_OAUTH_CLIENT_ID:?error}
      NOTION_OAUTH_CLIENT_SECRET: ${NOTION_OAUTH_CLIENT_SECRET:?error}
      NOTION_BASE_URL: ${NOTION_BASE_URL:?error}
      COS_SECRET_ID: ${COS_SECRET_ID:?error}
      COS_SECRET_KEY: ${COS_SECRET_KEY:?error}
      COS_BUCKET_APPID: ${COS_BUCKET_APPID:?error}
      COS_CUSTOM_DOMAIN: ${COS_CUSTOM_DOMAIN:?error}
      OPENAI_BASE_URL: ${OPENAI_BASE_URL:?error}
      OPENAI_API_KEY: ${OPENAI_API_KEY:?error}
      DB_HOST: ${DB_HOST:?error}
      DB_PORT: ${DB_PORT:?error}
      DB_USERNAME: ${DB_USERNAME:?error}
      DB_PASSWORD: ${DB_PASSWORD:?error}
      DB_NAME: ${DB_NAME:?error}
      YOUTUBE_API_KEY: ${YOUTUBE_API_KEY:?error}
      WECOM_BOT_WEBHOOK_URL: ${WECOM_BOT_WEBHOOK_URL:?error}
      WECOM_BOT_KEY: ${WECOM_BOT_KEY:?error}
      COZE_TRIGGER_001_WEBHOOK_URL: ${COZE_TRIGGER_001_WEBHOOK_URL:?error}
      COZE_TRIGGER_001_BEARER_TOKEN: ${COZE_TRIGGER_001_BEARER_TOKEN:?error}
    build:
      context: ./
      dockerfile: ./Dockerfile
    ports:
      - "${WEB_PORT:?error}:${WEB_PORT:?error}"
    networks:
      - dbnet
      - webnet
    depends_on:
      - db

networks:
  dbnet: {}
  webnet: {}

volumes:
  pgdata: {}
  logfiles: {}
